import'/namioshi/assets/style.css';

const GAME_URL='https://chameleonjp.codeberg.page/namioshi/',KEY='sb_publishable_drzcy0v97knU6FgjqSgBHw_0A9XPdFM',MAX_TAPS=3,PLAY=10;
const app=document.getElementById('app');app.innerHTML='<canvas id="c"></canvas><div id="hud" class="hud"><div class="pill">スコア <span id="s">0</span></div><div class="pill">残り <span id="t">10.0</span></div><div class="pill">タップ <span id="p">0</span>/3</div></div><section id="home" class="screen show"><div class="panel"><h1>namioshi</h1><p>暗い水面に波を押し、反射する波の線をビーコンに重ねる10秒ゲーム。</p><input id="name" class="input" maxlength="20" placeholder="名前"><button id="start" class="btn">開始</button><button class="btn secondary">ルール: 最大3タップ・高得点ほど上位</button><button id="hs" class="btn secondary">シェア</button><a class="link" href="https://chameleonjp.codeberg.page/" target="_blank">実験場リンク</a><p id="m" class="small warn"></p></div></section><section id="loading" class="screen"><div id="rt">LOADING</div></section><section id="ready" class="screen"><div id="rr">3</div></section><section id="result" class="screen"><div class="panel"><h1>RESULT</h1><p><b id="fs">0</b> 点</p><p id="rank" class="small"></p><button id="share" class="btn">シェア</button><button id="again" class="btn secondary">もう一度</button><textarea id="txt" class="shareText" readonly></textarea></div></section><section id="error" class="screen"><div class="panel"><h1>ERROR</h1><p id="err"></p></div></section>';
const $=id=>document.getElementById(id),cv=$('c');let ctx,gl,state='HOME',W=0,H=0,DPR=1,score=0,taps=0,time=PLAY,waves=[],beacons=[],glass=[],parts=[],player='',sent=false,last=0,q='MID',fps=[];
function screen(s){state=s;['home','loading','ready','result','error'].forEach(x=>$(x).classList.toggle('show',x===s.toLowerCase()));$('hud').classList.toggle('show',s==='PLAYING')}
function resize(){W=innerWidth;H=innerHeight;DPR=Math.min(devicePixelRatio||1,q==='LOW'?1:q==='HIGH'?1.5:1.25);cv.width=W*DPR;cv.height=H*DPR;cv.style.width=W+'px';cv.style.height=H+'px';if(ctx)ctx.setTransform(DPR,0,0,DPR,0,0)}
function init(){try{gl=cv.getContext('webgl',{antialias:false});ctx=cv.getContext('2d',{alpha:false});if(!ctx&&!gl)throw Error('no renderer');resize();addEventListener('resize',resize);cv.addEventListener('pointerdown',e=>{if(!e.isPrimary)return;e.preventDefault();if(state==='PLAYING'&&taps<MAX_TAPS){taps++;waves.push({x:e.clientX,y:e.clientY,r:1,w:9,a:0,hit:new Set,ref:0,kind:'direct',ed:new Set,ga:new Set});hud()}},{passive:false});requestAnimationFrame(loop)}catch(e){$('err').textContent=e.message;screen('ERROR')}}
function reset(){score=0;taps=0;time=PLAY;waves=[];parts=[];beacons=[0,1,2].map(i=>({id:i,x:(i+1)*W/4,y:H*(.3+i*.2),vx:8-i*8,vy:6,rad:16,f:0}));glass=[];for(let i=0;i<4;i++){let x=W*(.18+Math.random()*.64),y=H*(.22+Math.random()*.58),a=(Math.random()-.5)*1.8,l=70+Math.random()*45;glass.push({id:i,x1:x,y1:y,x2:x+Math.cos(a)*l,y2:y+Math.sin(a)*l,nx:-Math.sin(a),ny:Math.cos(a)})}sent=false;screen('PLAYING');hud()}
function ready(){screen('READY');let seq=['3','2','1','START'],i=0;$('rr').textContent=seq[0];let id=setInterval(()=>{i++;if(i<4)$('rr').textContent=seq[i];else{clearInterval(id);setTimeout(reset,400)}},700)}
function start(){player=$('name').value.trim();if(!player){$('m').textContent='名前を入力してください';return}screen('LOADING');setTimeout(ready,180)}
function addWave(x,y,ref,kind){if(waves.length<24)waves.push({x,y,r:1,w:9,a:0,hit:new Set,ref,kind,ed:new Set,ga:new Set})}
function step(dt){time-=dt;if(time<=0)return finish();for(const b of beacons){b.f=Math.max(0,b.f-dt*3);b.x+=b.vx*dt;b.y+=b.vy*dt;if(b.x<b.rad||b.x>W-b.rad)b.vx*=-1;if(b.y<70||b.y>H-b.rad)b.vy*=-1}for(let i=waves.length-1;i>=0;i--){let e=waves[i];e.a+=dt;e.r+=165*dt;if(e.ref<2){[['l',e.x,-e.x,e.y],['r',W-e.x,2*W-e.x,e.y],['t',e.y,e.x,-e.y],['b',H-e.y,e.x,2*H-e.y]].forEach(v=>{if(e.r>v[1]&&!e.ed.has(v[0])){e.ed.add(v[0]);addWave(v[2],v[3],e.ref+1,'wall')}});for(const g of glass){if(e.ga.has(g.id))continue;let vx=g.x2-g.x1,vy=g.y2-g.y1,len=vx*vx+vy*vy,t=Math.max(0,Math.min(1,((e.x-g.x1)*vx+(e.y-g.y1)*vy)/len)),px=g.x1+vx*t,py=g.y1+vy*t,per=(e.x-px)*g.nx+(e.y-py)*g.ny;if(Math.abs(Math.abs(per)-e.r)<9){e.ga.add(g.id);addWave(e.x-2*per*g.nx,e.y-2*per*g.ny,e.ref+1,'glass')}}}for(const b of beacons){if(e.hit.has(b.id))continue;let d=Math.hypot(e.x-b.x,e.y-b.y),err=Math.abs(d-e.r),band=e.w+b.rad*.35;if(err<=band){e.hit.add(b.id);let base=e.ref>=2?260:e.kind==='glass'?200:e.kind==='wall'?160:100;score+=Math.round(base*(1+(1-err/band)*.45));b.f=1;for(let k=0;k<12;k++)parts.push({x:b.x,y:b.y,vx:(Math.random()-.5)*120,vy:(Math.random()-.5)*120,a:0,l:.5})}}if(e.a>3)waves.splice(i,1)}for(let i=parts.length-1;i>=0;i--){let p=parts[i];p.a+=dt;p.x+=p.vx*dt;p.y+=p.vy*dt;if(p.a>p.l)parts.splice(i,1)}}
function draw(t){let c=ctx,g=c.createLinearGradient(0,0,0,H);g.addColorStop(0,'#06182b');g.addColorStop(1,'#01040b');c.fillStyle=g;c.fillRect(0,0,W,H);c.strokeStyle='rgba(110,230,255,.10)';for(let y=20;y<H;y+=18){c.beginPath();for(let x=0;x<W;x+=24)c.lineTo(x,y+Math.sin(x*.03+t*.002+y)*3);c.stroke()}c.lineCap='round';for(const g of glass){c.strokeStyle='rgba(220,250,255,.45)';c.lineWidth=5;c.beginPath();c.moveTo(g.x1,g.y1);c.lineTo(g.x2,g.y2);c.stroke()}for(const e of waves){c.strokeStyle='rgba(90,235,255,'+(1-e.a/3)*.8+')';c.lineWidth=3;c.beginPath();c.arc(e.x,e.y,e.r,0,7);c.stroke()}for(const b of beacons){let rg=c.createRadialGradient(b.x,b.y,2,b.x,b.y,b.rad*(3+b.f));rg.addColorStop(0,'#ffffe0');rg.addColorStop(1,'rgba(80,230,255,0)');c.fillStyle=rg;c.beginPath();c.arc(b.x,b.y,b.rad*(3+b.f),0,7);c.fill();c.fillStyle='#eaffff';c.beginPath();c.arc(b.x,b.y,b.rad,0,7);c.fill()}for(const p of parts){c.fillStyle='rgba(190,250,255,'+(1-p.a/p.l)+')';c.fillRect(p.x,p.y,2,2)}}
function hud(){$('s').textContent=score;$('t').textContent=Math.max(0,time).toFixed(1);$('p').textContent=taps}function finish(){if(state!=='PLAYING')return;screen('RESULT');$('fs').textContent=score;send()}async function send(){if(sent)return;sent=true;$('rank').textContent='ランキング送信中...';try{let r=await fetch('https://chameleonjp.supabase.co/rest/v1/rpc/submit_score',{method:'POST',headers:{apikey:KEY,Authorization:'Bearer '+KEY,'Content-Type':'application/json'},body:JSON.stringify({p_display_name:player,p_game_slug:'namioshi',p_score:score,p_client_version:'namioshi-v2.0.0'})});if(!r.ok)throw Error();$('rank').textContent='ランキング送信完了'}catch{$('rank').textContent='ランキング送信に失敗しました'}}
function st(sc=score){return '波押しで '+sc+'点！\n反射する波をビーコンに重ねた。\n'+GAME_URL}async function sh(sc=score){try{if(navigator.share)await navigator.share({text:st(sc)});else await navigator.clipboard.writeText(st(sc))}catch{let ta=$('txt');ta.style.display='block';ta.value=st(sc)}}
function loop(t){let dt=Math.min(.033,(t-last)/1000||0);last=t;if(state==='PLAYING'){step(dt);hud();if(taps>=MAX_TAPS&&waves.length===0)finish()}if(ctx)draw(t);fps.push(1/dt);if(fps.length>90){let a=fps.reduce((x,y)=>x+y,0)/fps.length;if(a<32)q='LOW';else if(a<45&&q==='MID')q='LOW';fps=[];resize()}requestAnimationFrame(loop)}
$('start').onclick=start;$('again').onclick=ready;$('share').onclick=()=>sh();$('hs').onclick=()=>sh(0);document.addEventListener('gesturestart',e=>e.preventDefault());init();
